const { ProjectClient } = require('magicbell-js/project-client');
const fs = require('fs');
const https = require('https');

async function main() {
  const runId = process.env.ZEALT_RUN_ID;
  const token = process.env.MAGICBELL_PROJECT_TOKEN;

  if (!runId) {
    throw new Error('ZEALT_RUN_ID environment variable is not set');
  }
  if (!token) {
    throw new Error('MAGICBELL_PROJECT_TOKEN environment variable is not set');
  }

  // Initialize ProjectClient (used to obtain the token)
  const client = new ProjectClient({ token });

  const workflowKey = `test-workflow-${runId}`;
  const url = `https://api.magicbell.com/workflows/${workflowKey}`;

  console.log(`Deleting workflow: ${workflowKey}`);

  const response = await fetch(url, {
    method: 'DELETE',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
  });

  const statusCode = response.status;
  console.log(`Response status: ${statusCode}`);

  const logContent = `Status: ${statusCode}`;
  fs.writeFileSync('/home/user/task/output.log', logContent);
  console.log(`Log written to /home/user/task/output.log`);
}

main().catch((err) => {
  console.error('Error:', err);
  process.exit(1);
});

